#[async_trait]
impl<R: FileLockProjectionRepository> FileLockEventHandler for FileLockProjector<R> {

    async fn on_created(&self, event: FileLockCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = FileLockProjection::new(
            event.id,
            event.file_id,
            event.user_id,
            event.locked_at,
            event.expires_at,
            event.refreshed_at,
            event.status,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: FileLockUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.file_id = event.file_id;
            projection.user_id = event.user_id;
            projection.locked_at = event.locked_at;
            projection.expires_at = event.expires_at;
            projection.refreshed_at = event.refreshed_at;
            projection.status = event.status;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: FileLockDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

